/// <summary>
///     The contract class for the container tracking report.
/// </summary>
[DataContractAttribute]
public class ETGContainerTrackingReportContract implements SysOperationValidatable
{
    TransDate                   fromDate;
    TransDate                   toDate;
    ETGITMShippingContainerId   containerId;

}

Method.Source:
[DataMemberAttribute('FromDate'), SysOperationLabelAttribute("@SYS36679"), SysOperationDisplayOrderAttribute('1')]
public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;

    return fromDate;
}

[DataMemberAttribute('ToDate'), SysOperationLabelAttribute("@SYS35904"), SysOperationDisplayOrderAttribute('2')]
public Transdate parmToDate(TransDate _ToDate = toDate)
{
    toDate = _toDate;

    return toDate;
}

[
    DataMemberAttribute('@ETG_New:ContainerId'),
    SysOperationLabelAttribute(literalStr("@ETG_New:ContainerId")),
    SysOperationHelpTextAttribute(literalStr("@ETG_New:ContainerId")),
    SysOperationDisplayOrderAttribute('3'),
    SysOperationGroupMemberAttribute('Container')
]
public ETGITMShippingContainerId parmContainerId(ETGITMShippingContainerId _containerId = containerId)
{
    containerId = _containerId;
    return containerId;
}

public boolean validate()
{
    boolean isValid = true;
    if (!fromDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180311"));
    }
    if (!toDate)
    {
        isValid = checkFailed(strFmt("@SYS84753", "@SYS180217"));
    }
    if (fromDate > toDate)
    {
        isValid = checkFailed("@SYS300457");
    }
    return isValid;
}
